#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; long long S; scanf("%lld %lld", &N, &S);
        __int128 total = (__int128)N * (N + 1) / 2;
        __int128 x = total - S;
        if(x >= 1 && x <= N) printf("%lld\n", (long long)x);
        else printf("-1\n");
    }
    return 0;
}

